import { useEffect, useState } from "react";
import axios from "axios";
import LoggedInNav from "../../../components/layout/LoggedInNav";
import ProfileLayout from "../../../components/profile/ProfileLayout";

export default function AdminProfilePage() {
  const [userData, setUserData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchUser = async () => {
      try {
        const userId = localStorage.getItem("userId");
        if (!userId) return;
        const res = await axios.get(`http://localhost:8080/users/${userId}`);
        setUserData(res.data);
      } catch (err) {
        console.error("Failed to load admin profile", err);
      } finally {
        setLoading(false);
      }
    };
    fetchUser();
  }, []);

  const handleUpdateProfile = async (payload) => {
    const userId = localStorage.getItem("userId");
    await axios.put(`http://localhost:8080/admin/${userId}/profile`, payload);
    setUserData(prev => ({ ...prev, name: payload.name }));
  };

  const handleChangePassword = async (payload) => {
    const userId = localStorage.getItem("userId");
    await axios.post(`http://localhost:8080/users/${userId}/change-password`, payload);
  };

  return (
    <div className="flex h-screen bg-surface-container-low font-body text-on-surface">
      <div className="flex-1 flex flex-col h-full overflow-hidden relative selection:bg-primary/20">
        <LoggedInNav />
        <main className="flex-1 overflow-y-auto p-6 md:p-10 pb-28 relative">
           <div className="absolute inset-0 bg-[radial-gradient(ellipse_at_top,_var(--tw-gradient-stops))] from-primary/5 via-surface to-surface pointer-events-none" />
           <div className="relative z-10 w-full">
            <ProfileLayout 
              userData={userData}
              role="ADMIN"
              loading={loading}
              onUpdateProfile={handleUpdateProfile}
              onChangePassword={handleChangePassword}
            />
           </div>
        </main>
      </div>
    </div>
  );
}
